arguments.newText:
if in_quotes:
    if char == '"':
        # Check for escaped quote (RFC 4180: "" inside quoted field = ")
        if i + 1 < len(text) and text[i + 1] == '"':
            current_field += '"'
            i += 1  # Skip the second quote
        else:
            in_quotes = False
    else:
        current_field += char
